-- Enrichment marathon batch: tldraw, TMetric, Toast, Toast Tables, Tock, Todoist, Together AI, Toggl Track

-- ── tldraw ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$tldraw is an open-source infinite canvas SDK and whiteboard app for React that lets developers embed drawing, diagramming, and multiplayer collaboration tools into their own products.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (app); SDK commercial license from $6,000/year$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$tldraw Review 2026: Pricing, Features and SDK Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$See how tldraw's infinite canvas whiteboard and React SDK work, what it costs, and how it compares for developers building drawing tools.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$tldraw is made by tldraw Inc, a London-based company founded by Steve Ruiz in 2022, building on an open source side project Ruiz started in 2021. The company offers two things under one brand: a free web app at tldraw.com for sketching, wireframing, and visual brainstorming, and the tldraw SDK, a React library that gives developers a production-ready infinite canvas editor to embed directly into their own products. The SDK is what sets tldraw apart from typical whiteboard tools, packaging the same rendering engine, shape system, and multiplayer sync layer that power tldraw.com into a library other companies can drop into their own interfaces. It underlies canvas features in ClickUp Whiteboards, Padlet Sandboxes, and Jam's screenshot annotation tool, plus experimental AI demos like make-real, which turns hand-drawn wireframes into working code. tldraw raised a 10 million dollar Series A in April 2025 led by Lux Capital and Definition Capital, with Amplify Partners also participating, bringing total funding to roughly 12 million dollars; the company says it closed just under 1 million dollars in SDK license deals in its first year of commercial operation. The consumer app is free with no paid tier. Commercial SDK use requires a license: free for development, hobby projects, and a 100-day trial, then 6,000 dollars per year (about 500 dollars per month) per team for production use, a flat fee introduced with SDK v4.0 that sparked debate over affordability for small startups. tldraw competes with Excalidraw, Miro's embeddable tooling, and Figma's canvas features, but its differentiator is developer embeddability rather than a hosted app alone.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3f6cc024-9f36-451d-b9e9-a8bc13712e95';

