-- ── TMetric ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TMetric is a time tracking and productivity app made by Devart that helps freelancers and teams log work hours, manage projects and budgets, and generate client-ready timesheets and invoices.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (up to 2 seats); paid plans from $7/user/month$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$51-200 employees (Devart)$q$, company_size),
  headquarters = COALESCE($q$Prague, Czech Republic$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$TMetric Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$TMetric time tracking software: pricing plans, key features, pros and cons, and who it's best for in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TMetric is a time tracking, timesheet, and productivity management application made by Devart, a Czech Republic-based database and developer tools company founded in 1997. TMetric began in 2016 as an internal productivity tool at Devart before being released publicly as a standalone product. It offers browser extensions, desktop apps for Windows, macOS and Linux, and mobile apps, letting individuals and teams track time against clients and projects, monitor budgets, capture screenshots and app or site activity, run payroll-ready reports, and sync with calendars. Pricing follows a freemium model: a Free plan supports up to two seats with unlimited time tracking, clients and projects, and reports; the Professional plan (around 7 dollars per user per month) adds billable rates, budgets, invoicing, and task management; the Business plan (around 9 dollars per user per month) adds screenshots, activity monitoring, time-off tracking, and integrations with QuickBooks, Jira, Redmine and ClickUp; and an Enterprise tier offers custom pricing, secure deployment, and volume discounts. TMetric integrates as a timer overlay inside more than 50 popular web apps, making it a lightweight alternative to standalone tools like Toggl Track, Time Doctor, or Harvest for teams that want tracking embedded directly into their existing project management tools. It targets freelancers, agencies, and small-to-midsize teams who need billing-grade time data without the overhead of enterprise workforce management software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6ca54283-3659-44f7-9c00-35f92eddfd5f';

