-- ── Toast Tables ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Toast Tables is Toast's reservation, waitlist, and table management add-on that helps restaurants seat guests, manage floor plans, and sync bookings with their Toast POS.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $50/month$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Part of Toast, Inc. (~5,700 employees)$q$, company_size),
  headquarters = COALESCE($q$Boston, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Toast Tables Review 2026: Reservation and Waitlist Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Toast Tables reservation and waitlist software: pricing, features, and how it fits into the Toast restaurant platform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Toast Tables is a restaurant reservation, waitlist, and table management product built by Toast, Inc., the Boston-based restaurant technology company founded in 2011 by Steve Fredette, Aman Narang, and Jonathan Grimm that also makes the Toast point-of-sale platform. Toast introduced Tables in April 2023 as an integrated add-on that connects guest bookings, host workflows, floor plans, and seating data directly with a restaurant's existing Toast POS system, rather than requiring a separate reservation platform like OpenTable or Resy that has to be manually reconciled with the POS. It runs as a host-facing app on an iPad or Android tablet, syncing with Toast Web so managers can configure settings, view bookings, and run reports from a browser. Hosts can seat walk-ins, add guests to a digital waitlist, text guests when their table is ready, accept both walk-in and online reservations, and pull up guest profiles that carry visit history and preferences from Toast's broader guest engagement tools. Toast has also integrated Tables with Google, letting diners search for and book a restaurant directly from its Google Business Profile. Pricing starts at 50 dollars per month for a plan that includes unlimited waitlist management and 25 reservations, with a Toast Tables Plus tier at 199 dollars per month offering unlimited reservations and waitlist together. Toast Tables is only available to restaurants already using or adopting the Toast POS ecosystem, positioning it as a bundled alternative to standalone reservation platforms such as OpenTable, Resy, or Tock for operators who want their front-of-house data unified with their point-of-sale system.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5a648195-23d1-462c-80b6-a9d18bdb505a';

