-- ── Tock ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tock is a reservation, waitlist, takeout, and events platform for restaurants, wineries, and hospitality venues, now owned by American Express.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $79/month$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Chicago, Illinois, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tock Review 2026: Pricing, Features for Restaurants$q$, seo_title),
  seo_meta_description = COALESCE($q$Tock reservation and dining platform: pricing plans, features, and how it compares to OpenTable and Resy in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tock is a reservation, waitlist, table management, takeout, and events platform for restaurants, wineries, hotels, and other hospitality venues. It was created in 2014 by Nick Kokonas, co-founder of Chicago's Alinea Group, who built the system to solve reservation and no-show problems he experienced running his own high-end restaurants, and Tock remains headquartered in Chicago, Illinois. The platform grew into an independent reservations company before Squarespace acquired it in 2021 for more than 400 million dollars in cash and stock to expand into hospitality commerce. In 2024, Squarespace agreed to sell Tock to American Express for roughly 400 million dollars as Amex looked to strengthen its dining and cardholder benefits ecosystem, alongside a related acquisition of the payments company Rooam; the deal closed in 2024, making Tock a unit of American Express rather than an independent or Squarespace-owned company. Tock serves several thousand restaurant, winery, and hotel customers and differentiates itself from OpenTable and Resy with a flat monthly subscription model that has no per-cover or per-reservation fee, instead charging a percentage on prepaid bookings and experiences such as prix-fixe dinners or ticketed events. Plans range from a Base tier starting around 79 dollars a month up through Essential, Plus, and Premium tiers that add lower prepayment fees, POS integrations, event and experience ticketing, and deeper guest analytics. Tock To Go, a separate takeout and delivery product, is priced at a flat 199 dollars a month plus a small percentage on orders.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3b848b09-87f9-4b49-ae0b-1296d600f752';

