-- ── Todoist ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Todoist is a task and project management app made by Doist that helps individuals and teams organize tasks, set reminders, and collaborate using natural language quick-add and cross-platform sync.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; Pro from $5/user/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$100+ employees (fully remote)$q$, company_size),
  headquarters = COALESCE($q$Palo Alto, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Todoist Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Todoist task management app: pricing plans, key features, pros and cons, and how it compares to other to-do apps in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Todoist is a task and project management app created by Amir Salihefendic and made by Doist Inc, a fully remote company with more than 100 employees across roughly 35 countries. Todoist launched in 2007, making it one of the longest-running task management apps still actively developed, and Doist has remained a bootstrapped, profitable company that has never taken venture capital funding, also building the team messaging app Twist. Todoist lets individuals and teams capture tasks with natural language quick-add, organize them into projects with sub-tasks, labels, and filters, set recurring due dates and reminders, and collaborate with shared projects, comments, and assigned tasks. It syncs across web, desktop (Windows, macOS, Linux), and mobile (iOS, Android) apps, and connects to more than 90 third-party integrations including calendar apps, Slack, and email. As of a December 2025 pricing update, Todoist offers three tiers: a free Beginner plan capped at 5 personal projects with basic reminders and views; a Pro plan for individuals at 5 dollars per user per month billed annually (7 dollars billed monthly) with up to 300 projects, full reporting history, task duration, and custom reminders; and a Business plan for teams at 8 dollars per user per month billed annually (10 dollars billed monthly) adding shared team workspaces, up to 500 team projects, roles and permissions, and centralized billing. Todoist competes with tools like TickTick, Things, Any.do, and broader project management platforms such as Asana and ClickUp, differentiating itself through a minimalist interface, fast natural language input, and a long track record of stability and cross-platform reliability.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '031d68c5-af3a-4399-8fac-121f0a02a529';

