-- ── Together AI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Together AI is an AI-native cloud platform providing inference APIs, GPU clusters, and fine-tuning for open-source and frontier AI models, used by developers and enterprises building AI applications.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Usage-based; inference from ~$0.05 per 1M tokens$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Together AI Review 2026: Pricing, Features, Funding$q$, seo_title),
  seo_meta_description = COALESCE($q$Together AI's inference cloud platform: pricing, key features, funding history, and how it compares for AI developers in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Together AI is an AI-native cloud computing company founded in June 2022 by CEO Vipul Ved Prakash along with Ce Zhang, Chris Re, Percy Liang, and Tri Dao, and headquartered in San Francisco, California. Prakash previously co-founded Cloudmark, an email security company, and Topsy, a social analytics company sold to Apple in 2013; Zhang, Re, and Liang bring academic AI research backgrounds from ETH Zurich, Stanford, and the University of Chicago. Together AI's platform provides serverless inference APIs for running open-source large language models, image and video generation models, and embedding and reranking models, alongside dedicated GPU instances, on-demand and reserved GPU clusters, code execution sandboxes, and fine-tuning infrastructure for training custom models. The company has raised roughly 900 million dollars across multiple funding rounds, including a 305 million dollar Series B led by General Catalyst, and in July 2026 raised an additional 800 million dollars at an 8.3 billion dollar valuation with participation from investors including Nvidia, Vista Equity Partners, and Aramco Ventures' venture arm. Pricing is entirely usage-based: serverless model inference is billed per token with rates spanning roughly 5 cents to several dollars per million tokens depending on model size and capability, image and video generation are billed per output, GPU clusters are billed per GPU-hour ranging from roughly 4 to 8 dollars on-demand with discounts for reserved capacity, and fine-tuning is billed per token processed during training. Together AI positions itself as a lower-cost, open-model-focused alternative to closed API providers like OpenAI and Anthropic, and as an alternative cloud infrastructure provider to AWS, Google Cloud, and Azure for AI-specific workloads such as training and high-throughput inference.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '95e1413b-980b-4a7c-a0da-8b7353d2474d';

