INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Infinite Canvas$q$, $q$Pan and zoom across an unbounded whiteboard surface for sketches, diagrams, and wireframes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Real-Time Multiplayer$q$, $q$Multiple users can draw and edit the same board simultaneously with live cursors and presence.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Full Shape Library$q$, $q$Built-in shapes including sticky notes, arrows, text, freehand drawing, images, embeds, and frames.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$React SDK$q$, $q$An embeddable, source-available React library for building custom canvas experiences inside other products.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Custom Shapes and Tools$q$, $q$Developers can define their own shape types, tools, and UI panels on top of the core engine.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Export Options$q$, $q$Boards export to SVG, PNG, or JSON for use elsewhere.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$AI and Code Generation Demos$q$, $q$Experimental features like make-real turn hand-drawn wireframes into working code.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Self-Hostable Multiplayer Backend$q$, $q$Teams can plug the SDK into their own storage and authentication instead of tldraw's hosted servers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Free and full-featured hosted whiteboard app for individuals and small teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Highly customizable SDK that lets developers embed a canvas rather than build one from scratch$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Proven at scale, powering canvas features in products like ClickUp and Padlet$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Active open-source-rooted community and fast-moving engineering team$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Real-time multiplayer collaboration built in from the start$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Commercial SDK license costs 6,000 dollars a year, a steep jump for early-stage startups$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$The consumer app lacks advanced project management or presentation features found in tools like Miro$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$SDK licensing terms and thresholds have changed over time, creating some uncertainty for adopters$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$No native mobile app beyond the responsive web experience$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Enterprise-level support and custom terms require direct sales contact rather than self-serve checkout$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Is tldraw free to use?$q$, $q$The tldraw.com whiteboard app is free for anyone to use. The tldraw SDK is free for development, hobby projects, and a 100-day trial, but commercial production use requires a paid license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$How much does the tldraw SDK cost?$q$, $q$The standard commercial license for the tldraw SDK costs 6,000 dollars per year, or about 500 dollars per month, per team.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Who makes tldraw?$q$, $q$tldraw is made by tldraw Inc, a London-based company founded by Steve Ruiz in 2022, building on an open source project Ruiz started in 2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$What is the tldraw SDK used for?$q$, $q$The SDK lets developers embed a full infinite canvas editor, including shapes, tools, and multiplayer sync, directly into their own web applications rather than building a canvas engine from scratch.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$What products use the tldraw SDK?$q$, $q$Known adopters include ClickUp Whiteboards, Padlet Sandboxes, and Jam's screenshot annotation feature, along with many smaller tools and internal products.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Does tldraw support real-time collaboration?$q$, $q$Yes, both the hosted app and SDK support real-time multiplayer editing with live cursors and shared presence.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Is tldraw open source?$q$, $q$tldraw's core began as an open source project, and parts of the codebase remain publicly viewable, but commercial production use of the SDK now requires a paid license under its source-available terms.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$How is tldraw different from Miro or Figma?$q$, $q$Unlike Miro or Figma, which are primarily hosted apps, tldraw's main differentiator is its embeddable SDK, letting other companies build their own branded whiteboard features on top of tldraw's canvas engine.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Embedding a Whiteboard in a SaaS Product$q$, $q$Product teams use the tldraw SDK to add native drawing and diagramming boards inside their own app, such as project management or design tools, without building a canvas engine from scratch.$q$, $q$Software engineering and product teams at SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Team Brainstorming and Wireframing$q$, $q$Designers and product managers use the free tldraw.com app for live sketching sessions, user flow diagrams, and quick wireframes during meetings.$q$, $q$Designers, product managers, and startup teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$AI Agent and Code Generation Demos$q$, $q$Developers use tldraw's canvas as an input surface for AI experiments that turn hand-drawn sketches into working interfaces or diagrams into structured data.$q$, $q$AI researchers and developers building generative design tools$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$Free (App)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited use of the tldraw.com whiteboard","Real-time multiplayer collaboration","Full shape and drawing tool library","Export to SVG, PNG, or JSON"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$SDK Trial$q$, $q$Free for 100 days$q$, $q$Trial$q$, NULL, $q$["Full access to the tldraw SDK for evaluation","Free for development and hobby projects indefinitely","Access to documentation and examples"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$SDK Commercial License$q$, $q$$6,000/year per team$q$, $q$Annual$q$, NULL, $q$["Production use of the tldraw SDK in a commercial product","Custom shapes, tools, and UI","Pluggable multiplayer backend","Priority engineering support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$overview$q$, $q$What Is tldraw$q$, 2, ARRAY[$q$tldraw is an infinite canvas whiteboard and SDK made by tldraw Inc, a London startup founded by Steve Ruiz in 2022 that grew out of an open source side project Ruiz began building in 2021. The company offers two things under one brand: a free consumer-facing whiteboard app at tldraw.com used by individuals and small teams for sketching, wireframing, and visual brainstorming, and the tldraw SDK, a React library that gives developers a production-ready infinite canvas editor they can embed directly into their own products.$q$, $q$The SDK is what sets tldraw apart from most whiteboard tools. Instead of only offering a hosted app, tldraw packages the same rendering engine, shape system, and multiplayer sync layer that power tldraw.com into a library other companies can drop into their own interfaces. This has made it the underlying canvas technology behind features like ClickUp Whiteboards, Padlet Sandboxes, and Jam's screenshot annotation tool, as well as countless internal tools and AI demo projects such as the viral make-real experiment that turns hand-drawn wireframes into working code.$q$, $q$tldraw raised a 10 million dollar Series A in April 2025 led by Lux Capital and Definition Capital, with Amplify Partners also participating, bringing total funding to roughly 12 million dollars. The company has said it closed just under 1 million dollars in SDK license deals in its first year of commercial operation, and it continues to develop both the free whiteboard app and the licensed SDK in parallel.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of tldraw is its infinite, zoomable canvas with a full shape library, including sticky notes, arrows, geometric shapes, freehand drawing, text, images, embeds, and frames, all rendered with the same tldraw shape engine whether you're using the hosted app or a custom embed built on the SDK. Multiplayer collaboration is built in, letting multiple people draw on the same canvas in real time with visible cursors and presence, and the app supports exporting boards as SVG, PNG, or JSON.$q$, $q$For developers, the SDK exposes a full API for defining custom shapes, tools, and UI, along with a pluggable multiplayer backend so teams can wire tldraw into their own auth and storage systems rather than depending on tldraw's hosted infrastructure. This customizability is why product teams choose it over building a canvas from scratch or licensing a closed source whiteboard engine.$q$, $q$tldraw also powers a set of experimental and AI-connected micro-products, including tools that convert freehand sketches into working UI code, which showcase how the canvas can serve as an input surface for AI agents and generative design workflows, not just static diagramming.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f6cc024-9f36-451d-b9e9-a8bc13712e95', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The tldraw.com whiteboard app is free to use with no paid consumer tier. For commercial use of the tldraw SDK in a shipped product, companies need a license: development and hobby projects can use the SDK for free, and there is a 100-day free trial for evaluating commercial use, after which a paid commercial license is required. The standard commercial license is priced at 6,000 dollars per year (roughly 500 dollars a month) per team, a flat fee introduced with SDK version 4.0 that sparked debate in the developer community over affordability for small startups.$q$, $q$tldraw has indicated it is open to extended trials and different terms for pre-revenue startups and companies working with incubators, and larger organizations with custom deployment or support needs can contact tldraw directly for enterprise terms. There is no self-serve tiered pricing beyond the flat commercial license at this time.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Cross-App Timer$q$, $q$Start and stop time tracking from inside more than 50 popular web apps without leaving your workflow.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Project Budgets and Alerts$q$, $q$Set budgets per project or client and get notified as spending approaches the limit.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Screenshot and Activity Monitoring$q$, $q$Business-tier screenshot capture and app or site usage tracking for team accountability.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Client Invoicing$q$, $q$Turn tracked billable hours directly into client-ready invoices.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Calendar Sync$q$, $q$Import calendar events as suggested time entries to reduce manual logging.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Time-Off Management$q$, $q$Track vacation, sick leave, and other time off alongside worked hours on the Business plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Reporting and Exports$q$, $q$Generate and export detailed timesheet and productivity reports for payroll or billing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Third-Party Integrations$q$, $q$Native integrations with Jira, Redmine, ClickUp, and QuickBooks.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Generous free plan with unlimited projects and clients for up to two seats$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Affordable per-seat pricing compared to many competing time trackers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Timer can be embedded inside dozens of other web apps for frictionless tracking$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Strong budgeting and invoicing tools for freelancers and agencies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Backed by Devart, an established developer tools company with decades of experience$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Interface and reporting feel more utilitarian than modern competitors like Toggl Track$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Screenshot and activity monitoring are gated behind the higher Business tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Fewer built-in integrations than larger time tracking platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Mobile app functionality is more limited than the desktop and web experience$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Enterprise pricing is not published and requires contacting sales$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Is TMetric free?$q$, $q$Yes, TMetric offers a free plan for up to two seats with unlimited time tracking, clients, and projects, though advanced features like budgets and screenshots require a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Who makes TMetric?$q$, $q$TMetric is made by Devart, a software company based in Prague, Czech Republic, that has built developer and database tools since 1997.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$How much does TMetric cost?$q$, $q$Paid plans start at roughly 7 dollars per user per month for the Professional tier, with the Business tier around 9 dollars per user per month; annual billing saves up to 20 percent.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Does TMetric track screenshots?$q$, $q$Screenshot capture and activity monitoring are available on the Business plan, not the Free or Professional tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Can TMetric generate invoices?$q$, $q$Yes, the Professional plan and above let you convert tracked billable hours into client invoices.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Does TMetric integrate with other tools?$q$, $q$TMetric integrates with project and accounting tools including Jira, Redmine, ClickUp, and QuickBooks, and its timer can run inside more than 50 other web apps.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$What platforms does TMetric support?$q$, $q$TMetric offers a web dashboard, browser extensions, desktop apps for Windows, macOS, and Linux, and mobile apps for iOS and Android.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Is TMetric good for freelancers?$q$, $q$Yes, many freelancers use the free plan or Professional tier for tracking billable hours, managing project budgets, and invoicing clients.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Freelance Time and Billing Tracking$q$, $q$Freelancers track billable hours across multiple clients, set project budgets, and generate invoices directly from logged time.$q$, $q$Independent freelancers and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Agency Team Time Management$q$, $q$Agencies use screenshots, activity monitoring, and team timesheets to track how staff time is spent across client projects.$q$, $q$Digital agencies and service teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Embedded Tracking Inside Existing Tools$q$, $q$Teams that already use Jira, ClickUp, or Redmine add TMetric's timer directly inside those apps to log time without switching tools.$q$, $q$Software and project teams using existing PM tools$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Free$q$, $q$$0$q$, $q$N/A (up to 2 seats)$q$, NULL, $q$["Unlimited time tracking","Unlimited clients and projects","Exportable reports","Timer in 50+ web apps","Desktop and mobile apps","API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Professional$q$, $q$$7/user/month$q$, $q$Monthly or annual (annual saves up to 20%)$q$, NULL, $q$["Everything in Free","Billable rates and expenses","Project budgets and alerts","Time rounding","Client invoicing","Calendar sync","Task management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Business$q$, $q$$9/user/month$q$, $q$Monthly or annual (annual saves up to 20%)$q$, NULL, $q$["Everything in Professional","Time-off module","Team timesheets","Screenshot capture and activity tracking","App and site monitoring","QuickBooks, Jira, Redmine, ClickUp integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Custom features and integrations","Priority support","Secure deployment options","Volume discounts"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$overview$q$, $q$What Is TMetric$q$, 2, ARRAY[$q$TMetric is a time tracking and timesheet application developed by Devart, a software company based in Prague, Czech Republic that has built database and developer tools since 1997. TMetric itself started life in 2016 as an internal tool Devart used to track its own team's productivity before the company decided to package it as a standalone product for external customers.$q$, $q$The tool is aimed at freelancers, agencies, and small-to-midsize teams that need to track billable hours, manage project budgets, and produce client-ready reports and invoices without adopting a heavier enterprise workforce management suite. It works as a lightweight timer that can be launched from inside more than 50 popular web apps, in addition to its own web dashboard, browser extensions, and native desktop and mobile apps.$q$, $q$Because Devart's core business is developer and database tooling, TMetric has a reputation among reviewers for being a stable, no-frills utility rather than a flashy product, with a straightforward feature set focused on accurate time capture, budgeting, and reporting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$TMetric's central feature is a start and stop timer that can be triggered from its own apps or embedded directly inside other web tools such as project trackers and helpdesks, so users don't have to switch context to log time against a task.$q$, $q$On the management side, TMetric offers project and client budgets with alerts when a project approaches its budget limit, billable and non-billable rate configuration, timesheet approvals, and client-ready invoicing. Team plans add screenshot capture and activity monitoring, app and website usage tracking, and a time-off module for tracking vacation and leave alongside worked hours.$q$, $q$TMetric connects to calendar apps for automatic time entry suggestions, and integrates with tools like Jira, Redmine, ClickUp, and QuickBooks so time data can flow into existing project management and accounting workflows rather than living in a silo.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ca54283-3659-44f7-9c00-35f92eddfd5f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TMetric uses a four-tier freemium model. The Free plan supports up to two seats and includes unlimited time tracking, unlimited clients and projects, exportable reports, and API access, making it usable for solo freelancers at no cost. The Professional plan, priced at roughly 7 dollars per user per month, adds billable rates and expenses, project budgets and alerts, time rounding, client invoicing, and calendar sync.$q$, $q$The Business plan, around 9 dollars per user per month and marked as TMetric's most popular tier, layers on the time-off module, team timesheets, screenshot capture, activity monitoring, and deeper integrations with tools like QuickBooks, Jira, and ClickUp. An Enterprise plan offers custom pricing with volume discounts, secure deployment options, and priority support for larger organizations. Annual billing on paid plans saves up to 20 percent compared to monthly billing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd25a08d-37be-447e-ac4c-280238739e44', $q$Android POS Terminals$q$, $q$Restaurant-built point-of-sale hardware with menu management, split checks, and tableside ordering.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd25a08d-37be-447e-ac4c-280238739e44', $q$Kitchen Display System$q$, $q$Routes orders to the right kitchen station in real time to speed up service.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd25a08d-37be-447e-ac4c-280238739e44', $q$Integrated Payment Processing$q$, $q$Card, contactless, and gift card payments processed directly through Toast's own terminals.$q$, 2);
